UPDATE lieux_tournage SET description_wikipedia = 'Le lac des Bouillouses (en catalan, Estany de la Bullosa ou de la Bollosa) est un lac artificiel d''une superficie de 149 ha des Pyrénées, en Haut-Conflent, dans les Pyrénées-Orientales.

(Source : Wikipédia, CC BY-SA)' WHERE id = 208;
UPDATE lieux_tournage SET description_wikipedia = 'Conat  est une commune française située dans le centre du département des Pyrénées-Orientales, en région Occitanie. Sur le plan historique et culturel, la commune est dans le pays de Conflent, correspondant à l''ensemble des vallées pyrénéennes qui « confluent » avec le lit creusé par la Têt entre Mont-Louis et Rodès.
