UPDATE lieux_tournage SET description_wikipedia = 'Le lycée et collège Georges-Clemenceau est un lycée de Montpellier, situé au 31, avenue Georges Clemenceau. Il est le premier lycée de filles de la ville et de France.

(Source : Wikipédia, CC BY-SA)' WHERE id = 142;
UPDATE lieux_tournage SET description_wikipedia = 'Saint-Denis-lès-Martel est une commune française, située dans le nord du département du Lot, en région Occitanie.
Elle est également dans le causse de Martel, une région naturelle constituant le plus septentrional des quatre causses du Quercy, entre Limousin, vallées de la Tourmente et de la Dordogne.
Exposée à un climat océanique altéré, elle est drainée par la Dordogne, la Sourdoire, la Tourmente et par divers autres petits cours d''eau.

(Source : Wikipédia, CC BY-SA)' WHERE id = 228;
UPDATE lieux_tournage SET description_wikipedia = 'Le château de la Mogère, localisé à Montpellier près du nouveau quartier d’Odysseum, est une folie montpelliéraine caractéristique, construite en 1715 et classé monument historique depuis 1945.

(Source : Wikipédia, CC BY-SA)' WHERE id = 145;
UPDATE lieux_tournage SET description_wikipedia = 'Lourdes est une commune française située dans l''ouest du département des Hautes-Pyrénées, en région Occitanie. Sur le plan historique et culturel, la commune est dans l’ancien comté de Bigorre, comté historique des Pyrénées françaises et de Gascogne.
Exposée à un climat océanique altéré, elle est drainée par le gave de Pau, le Mouscle, le Nès, le ruisseau des Graves et par divers autres petits cours d''eau.

(Source : Wikipédia, CC BY-SA)' WHERE id = 147;
UPDATE lieux_tournage SET description_wikipedia = 'Uzès [yzɛs] (Usès en occitan provençal, selon la norme classique) est une commune française située dans l''est du département du Gard, en région Occitanie.
Exposée à un climat méditerranéen, elle est drainée par  Les Seynes, l''Alzon et par Les Rosselles. Incluse dans les gorges du Gardon, la commune possède un patrimoine naturel remarquable composé d''une zone naturelle d''intérêt écologique, faunistique et floristique.

