UPDATE lieux_tournage SET description_wikipedia = 'Mont-Louis  est une commune française située dans le sud-ouest du département des Pyrénées-Orientales, en région Occitanie. Elle est inscrite depuis 2008 au patrimoine mondial de l''Unesco, avec onze autres fortifications de Vauban. Sur le plan historique et culturel, la commune est dans le pays de Conflent, correspondant à l''ensemble des vallées pyrénéennes qui « confluent » avec le lit creusé par la Têt entre Mont-Louis et Rodès.

